INSERT INTO public.sentences (german, translation_en, level, mode, language, chapter, lesson) VALUES
('Fast-response action potentials occur in atrial myocytes, ventricular myocytes, and Purkinje fibers.', 'These tissues rely on rapid sodium-channel activation for fast conduction.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Phase 0 of the fast-response action potential is produced by rapid inward sodium current.', 'The steepness of phase 0 is a major determinant of conduction velocity in working myocardium.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Phase 1 begins when sodium channels inactivate and transient outward potassium channels open.', 'This produces the brief initial fall in membrane voltage after depolarization.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('The phase 2 plateau results from calcium entry through L-type channels balancing potassium efflux.', 'Calcium entry during the plateau triggers calcium-induced calcium release and myocardial contraction.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Phase 3 repolarization occurs when calcium channels close and delayed-rectifier potassium currents dominate.', 'Potassium efflux returns the membrane toward its resting potential.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Phase 4 is stable in atrial and ventricular myocytes because of high resting potassium permeability.', 'A stable negative resting potential distinguishes working myocytes from pacemaker cells.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('SA- and AV-nodal cells do not have a stable resting membrane potential.', 'Their spontaneous phase 4 depolarization produces automaticity.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('The funny current contributes to spontaneous phase 4 depolarization in pacemaker cells.', 'Sympathetic stimulation steepens the phase 4 slope, whereas parasympathetic stimulation flattens it.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('The phase 0 upstroke in nodal tissue depends mainly on L-type calcium channels.', 'Because fast sodium channels are not responsible for the nodal upstroke, conduction through nodal tissue is relatively slow.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Pacemaker cells lack phases 1 and 2 of the action potential.', 'Their action potential is organized mainly around spontaneous phase 4 depolarization, calcium-mediated phase 0, and potassium-mediated phase 3.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Arrhythmias result from abnormal impulse formation, abnormal conduction, or both.', 'Classifying the mechanism helps explain the ECG pattern and therapeutic target.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Abnormal automaticity causes normally quiescent myocardial cells to develop spontaneous phase 4 depolarization.', 'Ischemia, metabolic disturbance, electrolyte imbalance, and catecholamine excess are common triggers.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Automatic rhythms often accelerate and decelerate gradually.', 'This behavior helps distinguish automatic tachycardias from re-entry rhythms that start and stop abruptly.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Triggered activity requires a preceding action potential and is mediated by afterdepolarizations.', 'The timing of the afterdepolarization determines whether it is classified as early or delayed.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Early afterdepolarizations occur during phases 2 or 3.', 'Bradycardia, hypokalemia, and QT-prolonging drugs promote EADs and may precipitate Torsades de pointes.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Delayed afterdepolarizations occur during phase 4 and are associated with intracellular calcium overload.', 'Digoxin toxicity and catecholamine excess are classic settings.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Re-entry is the most common mechanism of tachyarrhythmia.', 'It requires a circuit, unidirectional block, and sufficiently slow conduction for previously refractory tissue to recover.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('AVNRT, AVRT, atrial flutter, and scar-related monomorphic VT are classic re-entry arrhythmias.', 'These rhythms commonly begin and terminate abruptly.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('A QRS duration of 120 ms or less during tachycardia suggests activation through the normal His-Purkinje system.', 'The rhythm is therefore usually supraventricular in origin.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Irregular narrow-complex tachycardia suggests atrial fibrillation, atrial flutter with variable block, or multifocal atrial tachycardia.', 'Rhythm regularity is a rapid discriminator after QRS width is assessed.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('A regular wide-complex tachycardia in an adult with structural heart disease should be treated as ventricular tachycardia until proven otherwise.', 'Misclassification and inappropriate AV-nodal blockade can cause severe deterioration.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('An irregular wide-complex tachycardia may represent pre-excited atrial fibrillation, polymorphic VT, or atrial fibrillation with bundle-branch block.', 'Pre-excited atrial fibrillation is especially dangerous because ventricular rates can become extremely rapid.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('AV-nodal blockers are contraindicated in pre-excited atrial fibrillation.', 'Blocking the AV node can force conduction through the accessory pathway and precipitate ventricular fibrillation.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Hemodynamic instability caused by a tachyarrhythmia requires immediate synchronized cardioversion.', 'Hypotension, altered consciousness, ischemic chest discomfort, acute pulmonary edema, and syncope are warning features.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Synchronized cardioversion times the shock to the R wave.', 'Synchronization avoids delivering energy during the vulnerable T-wave period.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Unsynchronized defibrillation is indicated for ventricular fibrillation and pulseless ventricular tachycardia.', 'These non-perfusing shockable rhythms require immediate high-energy therapy.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Asystole and pulseless electrical activity are non-shockable rhythms.', 'Management depends on uninterrupted CPR, early epinephrine, and treatment of reversible causes.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Routine atropine is not recommended for asystole or pulseless electrical activity.', 'It does not replace CPR, epinephrine, or correction of the underlying cause.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('The reversible causes of cardiac arrest are summarized by the 5 Hs and 5 Ts.', 'A focused search for these causes should occur during resuscitation.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Progressive PR prolongation followed by a dropped QRS defines Mobitz type I AV block.', 'The block is usually nodal and is generally less dangerous than Mobitz type II.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Constant PR intervals with intermittent dropped QRS complexes define Mobitz type II AV block.', 'This infranodal block may progress suddenly to complete heart block and commonly requires pacing.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Complete heart block produces atrioventricular dissociation.', 'P waves and QRS complexes occur independently, usually with a slower ventricular escape rhythm.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Intermittent cannon A waves reflect atrial contraction against a closed tricuspid valve.', 'They are a bedside clue to atrioventricular dissociation in complete heart block or ventricular tachycardia.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Atropine is most effective for sinus bradycardia and AV-nodal block.', 'It may fail in infranodal high-grade block because the diseased tissue lies below the vagally responsive AV node.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Transcutaneous pacing is an immediate bridge for severe symptomatic bradycardia when medication is ineffective.', 'Temporary transvenous pacing may be required until definitive therapy is arranged.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Atrial fibrillation is characterized by absent discrete P waves and an irregularly irregular ventricular response.', 'The atria activate chaotically and contract ineffectively.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Atrial fibrillation commonly originates from triggers near the pulmonary vein ostia.', 'Catheter ablation frequently targets electrical isolation of the pulmonary veins.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Loss of atrial contraction in atrial fibrillation reduces late-diastolic ventricular filling.', 'The hemodynamic effect is greatest in patients with stiff or non-compliant ventricles.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Persistent rapid ventricular response can cause tachycardia-induced cardiomyopathy.', 'Rate or rhythm control can prevent or reverse progressive ventricular dysfunction.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Atrial flutter usually reflects a macro-re-entry circuit around the right atrial tricuspid annulus.', 'A 2:1 AV block commonly produces a ventricular rate near 150 beats per minute.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('AVNRT uses fast and slow pathways within or near the AV node.', 'Atrial and ventricular activation may be nearly simultaneous, hiding P waves within the QRS.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Orthodromic AVRT conducts antegradely through the AV node and retrogradely through an accessory pathway.', 'Because ventricular activation uses the His-Purkinje system, the QRS is usually narrow.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Wolff-Parkinson-White pattern includes a short PR interval, delta wave, and widened QRS.', 'These findings reflect ventricular pre-excitation through an accessory pathway.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Monomorphic ventricular tachycardia commonly arises from re-entry around a myocardial scar.', 'Prior myocardial infarction is a typical substrate.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Torsades de pointes is a polymorphic ventricular tachycardia associated with QT prolongation.', 'Magnesium is first-line therapy, while potassium and precipitating drugs should also be addressed.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Class IA antiarrhythmics prolong action-potential duration, refractory period, and QT interval.', 'Quinidine, procainamide, and disopyramide can therefore provoke Torsades de pointes.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Class IB drugs preferentially affect ischemic or depolarized ventricular tissue.', 'Lidocaine is useful for acute ventricular arrhythmias in the post-infarction setting.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Class IC drugs strongly block sodium channels and are contraindicated in structural or ischemic heart disease.', 'Flecainide and propafenone can be dangerously proarrhythmic in these patients.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Beta-blockers reduce the slope of phase 4 depolarization and suppress AV-nodal conduction.', 'They are useful for many supraventricular tachycardias, atrial fibrillation rate control, and post-MI arrhythmia prevention.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Class III drugs prolong phase 3 repolarization and the QT interval.', 'Sotalol and ibutilide have substantial Torsades risk, whereas amiodarone has broader extracardiac toxicity.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Verapamil and diltiazem slow AV-nodal conduction through L-type calcium-channel blockade.', 'They should be avoided in decompensated HFrEF and in undifferentiated wide-complex tachycardia.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Adenosine briefly blocks AV-nodal conduction.', 'It can terminate stable AV-node-dependent SVT and can reveal underlying atrial activity, but it must not be used in irregular wide-complex tachycardia.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Digoxin toxicity is promoted by hypokalemia and may cause multiple arrhythmias.', 'Associated clues include nausea, vomiting, and yellow visual disturbance.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('High-quality adult CPR uses a compression rate of 100 to 120 per minute and a depth of 5 to 6 cm.', 'Complete recoil and minimal interruptions are essential for coronary and cerebral perfusion.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Without an advanced airway, adult CPR uses a 30:2 compression-to-ventilation ratio.', 'After advanced-airway placement, compressions continue without pause while one breath is delivered every 6 seconds.', 'core', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('After ROSC, hypotension should be avoided and mean arterial pressure should be maintained at least around 65 mmHg.', 'The target should be individualized according to baseline physiology and clinical needs.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('After ROSC, oxygen should be titrated once reliable oximetry is available.', 'The source recommends an SpO2 target of 90% to 98% while avoiding both hypoxemia and hyperoxemia.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia'),
('Comatose patients after ROSC require protocolized temperature control and active fever prevention.', 'The source describes controlled temperature between 32°C and 37.5°C for at least 36 hours.', 'advanced', 'medical', 'en', 'Cardiology', 'Arrhythmia');
INSERT INTO public.words (german, translation, level, mode, category, chapter, lesson) VALUES
('Automaticity', 'The ability of cardiac cells to depolarize spontaneously and generate an impulse.', 'core', 'medical', 'Electrophysiology', 'Cardiology', 'Arrhythmia'),
('Funny current (If)', 'A mixed inward current that contributes to spontaneous phase 4 depolarization in pacemaker cells.', 'advanced', 'medical', 'Electrophysiology', 'Cardiology', 'Arrhythmia'),
('Effective refractory period', 'The interval during which a propagated cardiac action potential cannot be reinitiated.', 'advanced', 'medical', 'Electrophysiology', 'Cardiology', 'Arrhythmia'),
('Early afterdepolarization', 'An abnormal depolarization during phase 2 or 3 that is promoted by QT prolongation and may trigger Torsades de pointes.', 'core', 'medical', 'Mechanism', 'Cardiology', 'Arrhythmia'),
('Delayed afterdepolarization', 'An abnormal phase 4 depolarization caused by intracellular calcium overload.', 'core', 'medical', 'Mechanism', 'Cardiology', 'Arrhythmia'),
('Re-entry', 'Continuous circulation of an impulse through a circuit that repeatedly re-excites recovered myocardium.', 'core', 'medical', 'Mechanism', 'Cardiology', 'Arrhythmia'),
('Unidirectional block', 'Failure of conduction in one direction through part of a pathway, a prerequisite for many re-entry circuits.', 'advanced', 'medical', 'Mechanism', 'Cardiology', 'Arrhythmia'),
('Narrow-complex tachycardia', 'A tachycardia with QRS duration at or below 120 ms, usually indicating supraventricular origin.', 'core', 'medical', 'ECG', 'Cardiology', 'Arrhythmia'),
('Wide-complex tachycardia', 'A tachycardia with QRS duration above 120 ms caused by ventricular origin, aberrancy, pacing, or pre-excitation.', 'core', 'medical', 'ECG', 'Cardiology', 'Arrhythmia'),
('AV dissociation', 'Independent atrial and ventricular electrical activity, strongly supporting VT or complete heart block in the appropriate setting.', 'core', 'medical', 'ECG', 'Cardiology', 'Arrhythmia'),
('Pulse deficit', 'A difference between the apical heart rate and palpable peripheral pulse caused by ineffective ventricular contractions.', 'advanced', 'medical', 'Physical Examination', 'Cardiology', 'Arrhythmia'),
('AF-CARE pathway', 'A comprehensive atrial-fibrillation framework addressing comorbidities, stroke prevention, symptom reduction, and reassessment.', 'advanced', 'medical', 'Atrial Fibrillation', 'Cardiology', 'Arrhythmia'),
('Synchronized cardioversion', 'Electrical shock timed to the R wave for an unstable tachyarrhythmia with a pulse.', 'core', 'medical', 'Electrical Therapy', 'Cardiology', 'Arrhythmia'),
('Defibrillation', 'Unsynchronized high-energy shock used for ventricular fibrillation or pulseless ventricular tachycardia.', 'core', 'medical', 'Electrical Therapy', 'Cardiology', 'Arrhythmia'),
('Pulseless electrical activity', 'Organized electrical activity without a palpable pulse or effective mechanical circulation.', 'core', 'medical', 'Cardiac Arrest', 'Cardiology', 'Arrhythmia'),
('Asystole', 'Absence of meaningful cardiac electrical activity and mechanical output.', 'core', 'medical', 'Cardiac Arrest', 'Cardiology', 'Arrhythmia'),
('Return of spontaneous circulation', 'Restoration of a sustained palpable pulse and effective circulation after cardiac arrest.', 'core', 'medical', 'Cardiac Arrest', 'Cardiology', 'Arrhythmia'),
('Cannon A wave', 'A large intermittent JVP wave caused by atrial contraction against a closed tricuspid valve.', 'advanced', 'medical', 'Physical Examination', 'Cardiology', 'Arrhythmia'),
('First-degree AV block', 'PR prolongation above 200 ms with conduction of every atrial impulse.', 'core', 'medical', 'Bradyarrhythmia', 'Cardiology', 'Arrhythmia'),
('Mobitz type I block', 'Progressive PR prolongation followed by a non-conducted P wave.', 'core', 'medical', 'Bradyarrhythmia', 'Cardiology', 'Arrhythmia'),
('Mobitz type II block', 'Intermittent non-conducted P waves with constant PR intervals in conducted beats.', 'core', 'medical', 'Bradyarrhythmia', 'Cardiology', 'Arrhythmia'),
('Complete heart block', 'Total interruption of AV conduction with independent atrial and ventricular rhythms.', 'core', 'medical', 'Bradyarrhythmia', 'Cardiology', 'Arrhythmia'),
('Sinus node dysfunction', 'Impaired impulse formation or propagation by the sinoatrial node.', 'core', 'medical', 'Bradyarrhythmia', 'Cardiology', 'Arrhythmia'),
('Tachy-brady syndrome', 'Alternation between atrial tachyarrhythmias and symptomatic sinus pauses or bradycardia.', 'advanced', 'medical', 'Bradyarrhythmia', 'Cardiology', 'Arrhythmia'),
('Atrial fibrillation', 'Disorganized atrial activation with absent discrete P waves and an irregularly irregular ventricular rhythm.', 'core', 'medical', 'Supraventricular Arrhythmia', 'Cardiology', 'Arrhythmia'),
('Atrial flutter', 'Macro-re-entrant atrial tachycardia that often produces sawtooth flutter waves.', 'core', 'medical', 'Supraventricular Arrhythmia', 'Cardiology', 'Arrhythmia'),
('AVNRT', 'Atrioventricular nodal re-entrant tachycardia using fast and slow nodal pathways.', 'core', 'medical', 'Supraventricular Arrhythmia', 'Cardiology', 'Arrhythmia'),
('AVRT', 'Atrioventricular re-entrant tachycardia using the AV node and an accessory pathway as parts of the circuit.', 'core', 'medical', 'Supraventricular Arrhythmia', 'Cardiology', 'Arrhythmia'),
('Orthodromic AVRT', 'AVRT with antegrade conduction through the AV node and retrograde conduction through the accessory pathway.', 'advanced', 'medical', 'Supraventricular Arrhythmia', 'Cardiology', 'Arrhythmia'),
('Antidromic AVRT', 'AVRT with antegrade accessory-pathway conduction and retrograde AV-nodal conduction, usually producing a wide QRS.', 'advanced', 'medical', 'Supraventricular Arrhythmia', 'Cardiology', 'Arrhythmia'),
('Wolff-Parkinson-White syndrome', 'Pre-excitation caused by an accessory atrioventricular pathway capable of participating in tachyarrhythmia.', 'core', 'medical', 'Pre-excitation', 'Cardiology', 'Arrhythmia'),
('Delta wave', 'Slurred initial QRS upstroke caused by early ventricular activation through an accessory pathway.', 'core', 'medical', 'ECG', 'Cardiology', 'Arrhythmia'),
('Pre-excited atrial fibrillation', 'Atrial fibrillation conducting rapidly through an accessory pathway, producing an irregular wide-complex tachycardia.', 'advanced', 'medical', 'Emergency Arrhythmia', 'Cardiology', 'Arrhythmia'),
('Ventricular tachycardia', 'Three or more consecutive ventricular beats at a rapid rate; sustained VT lasts more than 30 seconds or causes instability.', 'core', 'medical', 'Ventricular Arrhythmia', 'Cardiology', 'Arrhythmia'),
('Torsades de pointes', 'Polymorphic ventricular tachycardia with QRS complexes twisting around the baseline in the setting of QT prolongation.', 'core', 'medical', 'Ventricular Arrhythmia', 'Cardiology', 'Arrhythmia'),
('Ventricular fibrillation', 'Chaotic ventricular electrical activity that produces no effective cardiac output.', 'core', 'medical', 'Ventricular Arrhythmia', 'Cardiology', 'Arrhythmia'),
('Vaughan Williams classification', 'Classification of antiarrhythmic drugs according to their principal electrophysiological action.', 'core', 'medical', 'Pharmacology', 'Cardiology', 'Arrhythmia'),
('Class IA antiarrhythmics', 'Moderate sodium-channel blockers that prolong action-potential duration, refractory period, and QT interval.', 'advanced', 'medical', 'Pharmacology', 'Cardiology', 'Arrhythmia'),
('Class IB antiarrhythmics', 'Weak sodium-channel blockers that shorten action-potential duration and preferentially affect ischemic ventricular tissue.', 'advanced', 'medical', 'Pharmacology', 'Cardiology', 'Arrhythmia'),
('Class IC antiarrhythmics', 'Strong sodium-channel blockers with major conduction slowing and proarrhythmic risk in structural heart disease.', 'advanced', 'medical', 'Pharmacology', 'Cardiology', 'Arrhythmia'),
('Class II antiarrhythmics', 'Beta-blockers that reduce sympathetic effects on SA- and AV-nodal tissue.', 'core', 'medical', 'Pharmacology', 'Cardiology', 'Arrhythmia'),
('Class III antiarrhythmics', 'Potassium-channel blockers that prolong repolarization, refractory period, and QT interval.', 'advanced', 'medical', 'Pharmacology', 'Cardiology', 'Arrhythmia'),
('Class IV antiarrhythmics', 'Non-dihydropyridine calcium-channel blockers that slow AV-nodal conduction.', 'core', 'medical', 'Pharmacology', 'Cardiology', 'Arrhythmia'),
('Adenosine', 'An ultra-short-acting AV-nodal blocker used for stable AV-node-dependent supraventricular tachycardia.', 'core', 'medical', 'Pharmacology', 'Cardiology', 'Arrhythmia'),
('Targeted temperature management', 'Protocolized temperature control and fever prevention in selected comatose patients after ROSC.', 'advanced', 'medical', 'Post-Arrest Care', 'Cardiology', 'Arrhythmia');
INSERT INTO public.dialogues (title_de, title_en, level, mode, lines, chapter, lesson) VALUES
('The First Minute of Tachycardia', 'Rapid assessment of an unstable tachyarrhythmia.', 'core', 'medical', '[{"speaker":"Attending","german":"A patient has a heart rate of 190 beats per minute. What is your first decision?","translation_en":"Determine whether the rhythm is causing hemodynamic instability."},{"speaker":"Resident","german":"I will assess blood pressure, mental status, ischemic chest pain, pulmonary edema, and syncope.","translation_en":"These findings indicate compromised perfusion."},{"speaker":"Attending","german":"The patient is hypotensive and confused but still has a pulse. What is the immediate treatment?","translation_en":"Immediate synchronized cardioversion."},{"speaker":"Resident","german":"I should not delay electrical treatment while completing a prolonged rhythm diagnosis.","translation_en":"Instability takes priority over detailed ECG classification."}]'::jsonb, 'Cardiology', 'Arrhythmia'),
('Regular Wide-Complex Tachycardia', 'Treating an undifferentiated wide rhythm safely.', 'core', 'medical', '[{"speaker":"Resident","german":"The ECG shows a regular tachycardia with a QRS duration of 160 ms.","translation_en":"This is a regular wide-complex tachycardia."},{"speaker":"Attending","german":"The patient has a previous myocardial infarction. What diagnosis should guide initial management?","translation_en":"Ventricular tachycardia until proven otherwise."},{"speaker":"Resident","german":"I will avoid empiric AV-nodal blockers that could worsen an incorrectly classified VT.","translation_en":"Safety favors treating structural-heart-disease patients as VT."},{"speaker":"Attending","german":"Which ECG relationship would further support VT?","translation_en":"Atrioventricular dissociation."}]'::jsonb, 'Cardiology', 'Arrhythmia'),
('Irregular Wide Tachycardia in WPW', 'Recognizing pre-excited atrial fibrillation.', 'advanced', 'medical', '[{"speaker":"Attending","german":"A young adult has an irregular, very rapid, wide-complex rhythm and a prior ECG with a delta wave.","translation_en":"This suggests pre-excited atrial fibrillation."},{"speaker":"Resident","german":"Can I give adenosine or diltiazem?","translation_en":"No. AV-nodal blockers are contraindicated."},{"speaker":"Attending","german":"Why are they dangerous?","translation_en":"They may force conduction down the accessory pathway and precipitate ventricular fibrillation."},{"speaker":"Resident","german":"If unstable, I will perform synchronized cardioversion; if stable, pathway-safe therapy such as procainamide is required.","translation_en":"Electrical therapy is immediate for instability."}]'::jsonb, 'Cardiology', 'Arrhythmia'),
('Progressive PR Prolongation', 'Distinguishing Mobitz I from Mobitz II.', 'core', 'medical', '[{"speaker":"Resident","german":"The PR interval becomes longer with each beat until one QRS is dropped.","translation_en":"This is Mobitz type I or Wenckebach block."},{"speaker":"Attending","german":"Where is the block usually located?","translation_en":"Within the AV node."},{"speaker":"Resident","german":"In Mobitz type II, the conducted PR intervals remain constant before unexpected dropped QRS complexes.","translation_en":"Mobitz II is usually infranodal and more dangerous."},{"speaker":"Attending","german":"What is the major clinical concern with Mobitz II?","translation_en":"Sudden progression to complete heart block."}]'::jsonb, 'Cardiology', 'Arrhythmia'),
('Atropine Failure', 'Escalating treatment for unstable bradycardia.', 'advanced', 'medical', '[{"speaker":"Attending","german":"A patient with complete heart block is hypotensive. Atropine produces no improvement.","translation_en":"Infranodal disease often responds poorly to atropine."},{"speaker":"Resident","german":"I will begin transcutaneous pacing and prepare for temporary transvenous pacing.","translation_en":"Pacing should not be delayed in profound instability."},{"speaker":"Attending","german":"Which infusions may support the rate while pacing is arranged?","translation_en":"Epinephrine or dopamine infusion."},{"speaker":"Resident","german":"After reversible causes are addressed, persistent complete block usually requires a permanent pacemaker.","translation_en":"Definitive therapy depends on reversibility and symptoms."}]'::jsonb, 'Cardiology', 'Arrhythmia'),
('Atrial Fibrillation Strategy', 'Integrating stroke prevention and symptom control.', 'advanced', 'medical', '[{"speaker":"Resident","german":"The ECG shows absent P waves and an irregularly irregular ventricular response.","translation_en":"The diagnosis is atrial fibrillation."},{"speaker":"Attending","german":"What two management questions must be addressed beyond confirming the rhythm?","translation_en":"Stroke prevention and rate-versus-rhythm control."},{"speaker":"Resident","german":"I will quantify thromboembolic risk and assess comorbidities such as hypertension, heart failure, obesity, and sleep apnea.","translation_en":"Risk-factor treatment is part of comprehensive AF care."},{"speaker":"Attending","german":"What changes if the patient is hypotensive with pulmonary edema?","translation_en":"Immediate synchronized cardioversion is required."}]'::jsonb, 'Cardiology', 'Arrhythmia'),
('Twisting QRS Complexes', 'Managing Torsades de pointes.', 'core', 'medical', '[{"speaker":"Resident","german":"The monitor shows polymorphic VT with complexes twisting around the baseline.","translation_en":"This is Torsades de pointes."},{"speaker":"Attending","german":"Which predisposing abnormalities should you seek?","translation_en":"QT-prolonging drugs, hypokalemia, hypomagnesemia, and bradycardia."},{"speaker":"Resident","german":"I will give intravenous magnesium and correct the precipitating factors.","translation_en":"Magnesium is first-line therapy."},{"speaker":"Attending","german":"What electrophysiological mechanism commonly initiates it?","translation_en":"Early afterdepolarizations during phases 2 or 3."}]'::jsonb, 'Cardiology', 'Arrhythmia'),
('Shockable Cardiac Arrest', 'Defibrillation and CPR sequence in VF.', 'core', 'medical', '[{"speaker":"Team Leader","german":"The patient is pulseless and the monitor shows ventricular fibrillation.","translation_en":"VF is a shockable cardiac-arrest rhythm."},{"speaker":"Nurse","german":"The defibrillator is ready.","translation_en":"Deliver an immediate unsynchronized shock."},{"speaker":"Team Leader","german":"Resume compressions immediately after the shock for two minutes.","translation_en":"Do not pause immediately for a pulse check."},{"speaker":"Resident","german":"Epinephrine follows failed initial defibrillation attempts, and amiodarone or lidocaine may be considered for refractory VF.","translation_en":"Drug timing differs from the non-shockable pathway."}]'::jsonb, 'Cardiology', 'Arrhythmia'),
('Pulseless Electrical Activity', 'Non-shockable arrest and reversible causes.', 'core', 'medical', '[{"speaker":"Resident","german":"The monitor shows an organized rhythm, but no pulse is palpable.","translation_en":"This is pulseless electrical activity."},{"speaker":"Attending","german":"Should we defibrillate?","translation_en":"No. PEA is non-shockable."},{"speaker":"Resident","german":"We will continue high-quality CPR, give epinephrine early, and search for the 5 Hs and 5 Ts.","translation_en":"Correcting the underlying cause is central to survival."},{"speaker":"Attending","german":"Would routine atropine improve the algorithm?","translation_en":"No. Routine atropine is not recommended for PEA or asystole."}]'::jsonb, 'Cardiology', 'Arrhythmia'),
('Post-Arrest Stabilization', 'Care after return of spontaneous circulation.', 'advanced', 'medical', '[{"speaker":"Intensivist","german":"ROSC has been achieved. What immediate physiologic threats must we avoid?","translation_en":"Hypotension, hypoxemia, hyperoxemia, and inappropriate ventilation."},{"speaker":"Resident","german":"I will maintain a MAP of at least about 65 mmHg and titrate oxygen after reliable oximetry is available.","translation_en":"Targets should be individualized while avoiding extremes."},{"speaker":"Intensivist","german":"The patient remains comatose. What neuroprotective step is required?","translation_en":"Protocolized temperature control with strict fever prevention."},{"speaker":"Resident","german":"Persistent ST elevation would prompt urgent coronary angiography.","translation_en":"Coronary and neurologic care proceed in parallel."}]'::jsonb, 'Cardiology', 'Arrhythmia');
INSERT INTO public.long_texts (title_de, title_en, body_de, translation_en, level, mode, chapter, lesson) VALUES
('Case Study: Unstable Regular Narrow-Complex Tachycardia', 'Immediate synchronized cardioversion takes priority over rhythm refinement.', 'A 48-year-old patient develops abrupt palpitations, diaphoresis, and dyspnea. The monitor shows a regular narrow-complex tachycardia at 190 beats per minute. Blood pressure is 74/40 mmHg, the patient is confused, and crackles are heard over both lungs. Intravenous access and continuous monitoring are established while a 12-lead ECG is obtained without delaying treatment.', 'Diagnosis and takeaway: The rhythm is a tachyarrhythmia with clear hemodynamic instability. Immediate synchronized cardioversion is required because hypotension, altered mental status, and acute pulmonary edema indicate inadequate perfusion. A prolonged attempt to distinguish AVNRT, AVRT, or atrial tachycardia must not delay electrical therapy.', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Case Study: Wide-Complex Tachycardia After Myocardial Infarction', 'Structural heart disease strongly favors ventricular tachycardia.', 'A 67-year-old patient with a previous anterior myocardial infarction presents with sudden palpitations. The ECG shows a regular rhythm at 165 beats per minute with a QRS duration of 170 ms. P waves appear to march independently of the QRS complexes. The blood pressure is initially preserved.', 'Diagnosis and takeaway: This is ventricular tachycardia until proven otherwise. The prior infarction provides a scar substrate for re-entry, and AV dissociation strongly supports VT. Empiric AV-nodal blockers should be avoided in an undifferentiated wide-complex tachycardia. If instability develops, synchronized cardioversion is required.', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Case Study: Pre-Excited Atrial Fibrillation', 'An irregular wide-complex rhythm with WPW features is a high-risk emergency.', 'A 24-year-old patient with a known short PR interval and delta wave develops severe palpitations. The ECG shows an irregular, extremely rapid, wide-complex tachycardia with changing QRS morphology. The patient is anxious but currently maintains blood pressure.', 'Diagnosis and takeaway: The likely diagnosis is pre-excited atrial fibrillation conducting through an accessory pathway. Adenosine, beta-blockers, verapamil, diltiazem, and digoxin are contraindicated because AV-nodal blockade may accelerate accessory-pathway conduction and precipitate ventricular fibrillation. An unstable patient requires synchronized cardioversion; a stable patient requires pathway-safe therapy such as procainamide and definitive accessory-pathway ablation.', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Case Study: Mobitz Type II AV Block', 'Unexpected dropped beats with fixed PR intervals signal dangerous infranodal disease.', 'A 72-year-old patient reports recurrent presyncope. The ECG shows sinus P waves with constant PR intervals in conducted beats, but every third P wave is not followed by a QRS complex. The QRS complexes are broad. The patient becomes hypotensive during observation.', 'Diagnosis and takeaway: The tracing is consistent with Mobitz type II AV block, usually arising in the His-Purkinje system. The broad QRS and symptoms increase concern for progression to complete heart block. Atropine may be ineffective. Immediate pacing support should be prepared, with transcutaneous pacing as a bridge to transvenous and potentially permanent pacing.', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Case Study: Tachy-Brady Syndrome', 'Atrial tachyarrhythmia termination can expose severe sinus-node dysfunction.', 'A 76-year-old patient describes alternating episodes of rapid palpitations and near-syncope. Ambulatory monitoring records atrial fibrillation followed by a six-second sinus pause when the tachycardia terminates. Several medications that slow the AV node are being considered for symptom control.', 'Diagnosis and takeaway: This is tachy-brady syndrome, a form of sinus-node dysfunction. The long post-tachycardia pause explains the near-syncope. Rate-controlling drugs may worsen bradycardia, so pacing may be needed to permit safe treatment of the atrial tachyarrhythmia.', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Case Study: Torsades After QT-Prolonging Medication', 'Early afterdepolarizations link prolonged QT to polymorphic VT.', 'A hospitalized patient receives a QT-prolonging drug and subsequently develops hypokalemia. Telemetry shows recurrent bursts of polymorphic ventricular tachycardia in which the QRS complexes appear to twist around the isoelectric line. The episodes are associated with dizziness and transient loss of consciousness.', 'Diagnosis and takeaway: The rhythm is Torsades de pointes. QT prolongation, hypokalemia, and relative bradycardia promote early afterdepolarizations during phases 2 and 3. Intravenous magnesium is first-line treatment, and potassium deficiency and offending drugs must be corrected. If the rhythm becomes pulseless, immediate defibrillation and CPR are required.', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Case Study: Digoxin Toxicity', 'Calcium overload and hypokalemia create a proarrhythmic state.', 'An older patient taking digoxin presents with nausea, vomiting, yellow-tinted vision, and palpitations. Laboratory testing shows hypokalemia. The ECG demonstrates frequent ectopy and variable atrial and ventricular arrhythmias.', 'Diagnosis and takeaway: Digoxin toxicity causes intracellular calcium accumulation and delayed afterdepolarizations. Hypokalemia increases toxicity risk. Recognition depends on the combination of gastrointestinal symptoms, visual disturbance, electrolyte abnormalities, and diverse arrhythmias. The causative drug and electrolyte disturbance must be addressed urgently.', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Case Study: Ventricular Fibrillation Arrest', 'Shock first, then resume high-quality CPR immediately.', 'A patient collapses in the emergency department and is unresponsive with abnormal gasping. No definite pulse is felt within 10 seconds. The monitor shows a chaotic rhythm without identifiable QRS complexes. A biphasic defibrillator is immediately available.', 'Diagnosis and takeaway: This is ventricular fibrillation, a shockable cardiac-arrest rhythm. Deliver unsynchronized defibrillation immediately, then resume high-quality CPR for two minutes without pausing for an immediate pulse check. Epinephrine is introduced after initial shocks fail, and amiodarone or lidocaine may be considered for refractory VF.', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Case Study: Pulseless Electrical Activity From Tension Pneumothorax', 'The electrical rhythm is not the diagnosis; the reversible cause must be found.', 'A mechanically ventilated patient suddenly becomes hypotensive and unresponsive. The monitor shows organized electrical complexes, but no carotid pulse is present. Breath sounds are absent on one side, and the trachea is displaced.', 'Diagnosis and takeaway: This is pulseless electrical activity caused by tension pneumothorax, one of the reversible Ts. Defibrillation is ineffective. Management requires immediate CPR and epinephrine while urgently relieving the tension pneumothorax. The case illustrates why the 5 Hs and 5 Ts must be investigated during non-shockable arrest.', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Case Study: Comatose Patient After ROSC', 'Post-arrest care requires coordinated hemodynamic, respiratory, coronary, and neurologic management.', 'After successful resuscitation from ventricular fibrillation, a patient has a palpable pulse but remains comatose. Blood pressure is 82/48 mmHg, oxygen saturation is initially measured while receiving 100% oxygen, and the ECG shows persistent ST-segment elevation.', 'Diagnosis and takeaway: Post-ROSC care should prevent hypotension, with a MAP target of at least about 65 mmHg individualized to the patient. Oxygen should be titrated once reliable oximetry is available, avoiding both hypoxemia and hyperoxemia. Coma requires protocolized temperature control and fever prevention. Persistent ST elevation supports urgent coronary angiography.', 'advanced', 'medical', 'Cardiology', 'Arrhythmia');
INSERT INTO public.grammar_exercises (question, options, correct_answer, explanation, topic, level, mode, chapter, lesson) VALUES
('Which ion current primarily produces phase 0 in ventricular myocytes?', '["Rapid inward sodium current","Slow inward calcium current","Outward chloride current","Funny current"]', 'Rapid inward sodium current', 'Fast voltage-gated sodium channels generate the rapid phase 0 upstroke in atrial and ventricular myocytes and Purkinje fibers.', 'Action Potentials', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which event best describes phase 2 of the ventricular action potential?', '["Calcium entry balances potassium efflux","Sodium channels produce spontaneous depolarization","Potassium permeability creates the funny current","Calcium channels close before depolarization"]', 'Calcium entry balances potassium efflux', 'The plateau phase is maintained by L-type calcium entry opposing potassium efflux and triggers contraction.', 'Action Potentials', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which phase determines pacemaker automaticity and heart rate most directly?', '["Phase 4 spontaneous depolarization","Phase 1 initial repolarization","Phase 2 plateau","Stable phase 4 resting potential"]', 'Phase 4 spontaneous depolarization', 'The slope of spontaneous phase 4 depolarization determines how quickly pacemaker cells reach threshold.', 'Action Potentials', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('The upstroke of the AV-nodal action potential depends mainly on which channels?', '["L-type calcium channels","Fast sodium channels","Transient outward potassium channels","Chloride channels"]', 'L-type calcium channels', 'Nodal tissue uses a slow calcium-mediated phase 0 rather than the fast sodium-mediated upstroke of working myocardium.', 'Action Potentials', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Which combination is required for a re-entry circuit?', '["Potential circuit, unidirectional block, and slow conduction","Prolonged PR, bilateral block, and rapid conduction","Hyperkalemia, acidosis, and ischemia","Two simultaneous sinus impulses and AV block"]', 'Potential circuit, unidirectional block, and slow conduction', 'Re-entry requires a circuit, a unidirectional conduction block, and enough delay for previously refractory tissue to recover.', 'Arrhythmia Mechanisms', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('A tachycardia that starts and stops abruptly is most suggestive of which mechanism?', '["Re-entry","Abnormal automaticity","Sinus acceleration","Progressive conduction failure"]', 'Re-entry', 'Re-entry rhythms often have abrupt onset and termination, whereas automatic rhythms tend to warm up and cool down.', 'Arrhythmia Mechanisms', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Early afterdepolarizations are most strongly associated with which setting?', '["Bradycardia and prolonged QT","Tachycardia and shortened QT","Hypercalcemia without a prior action potential","First-degree AV block"]', 'Bradycardia and prolonged QT', 'EADs occur during phases 2 or 3 and are promoted by bradycardia, hypokalemia, and QT-prolonging drugs.', 'Arrhythmia Mechanisms', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Delayed afterdepolarizations are classically caused by which abnormality?', '["Intracellular calcium overload","Loss of all potassium permeability","Complete sodium-channel inactivation at rest","Atrial fibrosis alone"]', 'Intracellular calcium overload', 'DADs occur during phase 4 and are associated with calcium overload, as in digoxin toxicity or catecholamine excess.', 'Arrhythmia Mechanisms', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('A QRS duration of 110 ms during tachycardia most strongly suggests what?', '["Ventricular activation through the normal His-Purkinje system","Mandatory ventricular tachycardia","Complete infra-Hisian block","Ventricular fibrillation"]', 'Ventricular activation through the normal His-Purkinje system', 'A QRS at or below 120 ms is narrow and usually indicates supraventricular origin with normal ventricular activation.', 'ECG Classification', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which rhythm is an irregular narrow-complex tachycardia?', '["Atrial fibrillation","AVNRT","Monomorphic ventricular tachycardia","Orthodromic AVRT"]', 'Atrial fibrillation', 'Atrial fibrillation is classically irregularly irregular with a narrow QRS unless aberrancy or pre-excitation is present.', 'ECG Classification', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('A patient with prior myocardial infarction has a regular wide-complex tachycardia. What is the safest initial assumption?', '["Ventricular tachycardia","Sinus tachycardia","Atrial fibrillation","Mobitz type I block"]', 'Ventricular tachycardia', 'A regular wide-complex tachycardia in structural heart disease should be treated as VT until proven otherwise.', 'ECG Classification', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which finding most strongly supports VT in a wide-complex tachycardia?', '["AV dissociation","Progressive PR prolongation","Sawtooth flutter waves","A short isolated PR interval"]', 'AV dissociation', 'Independent atrial and ventricular activity strongly supports a ventricular origin.', 'ECG Classification', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Which rhythm is classically irregular and wide complex?', '["Pre-excited atrial fibrillation","Typical AVNRT","Sinus tachycardia","Atrial flutter with fixed 2:1 conduction"]', 'Pre-excited atrial fibrillation', 'Pre-excited AF produces very rapid, irregular, wide complexes because atrial impulses conduct through an accessory pathway.', 'ECG Classification', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('A patient with tachycardia has hypotension, confusion, and a palpable pulse. What is the immediate treatment?', '["Synchronized cardioversion","Unsynchronized defibrillation","Oral beta-blocker","Observation until the ECG diagnosis is complete"]', 'Synchronized cardioversion', 'An unstable tachyarrhythmia with a pulse requires immediate synchronized cardioversion.', 'Emergency Management', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Why is synchronized cardioversion timed to the R wave?', '["To avoid shocking during the vulnerable T wave","To prolong the PR interval","To generate a delta wave","To increase automaticity"]', 'To avoid shocking during the vulnerable T wave', 'R-wave synchronization reduces the risk of an R-on-T shock precipitating ventricular fibrillation.', 'Electrical Therapy', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which rhythm requires unsynchronized defibrillation?', '["Ventricular fibrillation","Atrial fibrillation with a pulse","Stable AVNRT","Mobitz type II block"]', 'Ventricular fibrillation', 'VF is a non-perfusing shockable rhythm requiring immediate unsynchronized defibrillation.', 'Electrical Therapy', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which cardiac-arrest rhythm is non-shockable?', '["Pulseless electrical activity","Pulseless ventricular tachycardia","Ventricular fibrillation","Unstable polymorphic VT without a pulse"]', 'Pulseless electrical activity', 'PEA and asystole are treated with CPR, epinephrine, and reversal of the underlying cause rather than defibrillation.', 'Cardiac Arrest', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('What is the standard epinephrine dose described for adult cardiac arrest?', '["1 mg IV/IO every 3 to 5 minutes","0.1 mg IV every 30 minutes","5 mg IM once","10 mg IV after every shock"]', '1 mg IV/IO every 3 to 5 minutes', 'The source specifies epinephrine 1 mg IV/IO every 3 to 5 minutes.', 'Cardiac Arrest', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which is one of the 5 Hs of reversible cardiac arrest causes?', '["Hypoxia","Hypertension","Hyperthyroidism","Hemorrhagic stroke"]', 'Hypoxia', 'The 5 Hs are hypovolemia, hypoxia, hydrogen ion excess, hypo-/hyperkalemia, and hypothermia.', 'Cardiac Arrest', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which is one of the 5 Ts of reversible cardiac arrest causes?', '["Tension pneumothorax","Tachy-brady syndrome","Tricuspid regurgitation","Tetralogy of Fallot"]', 'Tension pneumothorax', 'Tension pneumothorax is a reversible cause of arrest included among the 5 Ts.', 'Cardiac Arrest', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which ECG pattern defines first-degree AV block?', '["PR interval longer than 200 ms with every P wave conducted","Progressive PR shortening before a dropped QRS","Constant PR intervals with dropped QRS complexes","Complete absence of P waves"]', 'PR interval longer than 200 ms with every P wave conducted', 'First-degree block is delayed AV conduction without dropped beats.', 'Bradyarrhythmia', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which ECG finding defines Mobitz type I AV block?', '["Progressive PR prolongation followed by a dropped QRS","Constant PR intervals with random dropped QRS complexes","Independent P waves and QRS complexes","Short PR with delta wave"]', 'Progressive PR prolongation followed by a dropped QRS', 'Wenckebach conduction shows gradual PR lengthening until a beat is not conducted.', 'Bradyarrhythmia', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which ECG finding defines Mobitz type II AV block?', '["Constant PR intervals with intermittent dropped QRS complexes","Progressive PR prolongation before every QRS","Absent P waves with irregular RR intervals","Sawtooth flutter waves"]', 'Constant PR intervals with intermittent dropped QRS complexes', 'Mobitz II reflects intermittent infranodal conduction failure without progressive PR lengthening.', 'Bradyarrhythmia', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Why is Mobitz type II generally more dangerous than Mobitz type I?', '["It may progress suddenly to complete heart block","It always causes atrial fibrillation","It is caused only by vagal tone","It cannot produce syncope"]', 'It may progress suddenly to complete heart block', 'Mobitz II is usually infranodal and has a substantial risk of abrupt progression.', 'Bradyarrhythmia', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which finding characterizes complete heart block?', '["Independent atrial and ventricular rhythms","Every P wave followed by a QRS with prolonged PR","Irregularly irregular rhythm without P waves","Narrow tachycardia with hidden P waves"]', 'Independent atrial and ventricular rhythms', 'Third-degree AV block produces complete AV dissociation.', 'Bradyarrhythmia', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Intermittent cannon A waves are most directly caused by what?', '["Atrial contraction against a closed tricuspid valve","Ventricular contraction against a closed aortic valve","Loss of all atrial contraction","Continuous tricuspid opening"]', 'Atrial contraction against a closed tricuspid valve', 'AV dissociation occasionally causes the atrium to contract when the tricuspid valve is closed.', 'Physical Examination', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Why may atropine fail in complete infranodal heart block?', '["The diseased conduction tissue lies below the vagally responsive AV node","Atropine blocks sodium channels","Atropine prolongs the QT interval","The SA node has no muscarinic receptors"]', 'The diseased conduction tissue lies below the vagally responsive AV node', 'Removing vagal tone may not improve conduction through damaged His-Purkinje tissue.', 'Bradyarrhythmia Management', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('What is the next immediate step when unstable bradycardia does not respond to atropine?', '["Initiate transcutaneous pacing","Give adenosine","Perform unsynchronized defibrillation","Administer verapamil"]', 'Initiate transcutaneous pacing', 'Pacing is an urgent bridge when pharmacologic therapy fails or the patient is profoundly unstable.', 'Bradyarrhythmia Management', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which ECG description is most characteristic of atrial fibrillation?', '["Absent discrete P waves with irregularly irregular RR intervals","Regular sawtooth waves with fixed RR intervals","Short PR with delta wave in every case","Progressive PR prolongation"]', 'Absent discrete P waves with irregularly irregular RR intervals', 'AF causes disorganized atrial activity and an irregular ventricular response.', 'Atrial Fibrillation', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('What is the most common trigger location for atrial fibrillation described in the source?', '["Pulmonary vein ostia","AV node","Right bundle branch","Ventricular apex"]', 'Pulmonary vein ostia', 'Rapidly depolarizing cells near the pulmonary veins commonly initiate AF.', 'Atrial Fibrillation', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Which patient is most likely to be adversely affected by loss of atrial kick?', '["A patient with a stiff hypertrophied ventricle","A healthy child with normal ventricular compliance","A patient with isolated sinus tachycardia","A patient with a normal resting ECG and no structural disease"]', 'A patient with a stiff hypertrophied ventricle', 'Late-diastolic atrial contraction is particularly important when ventricular compliance is reduced.', 'Atrial Fibrillation', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Persistent uncontrolled rapid AF can cause which complication?', '["Tachycardia-induced cardiomyopathy","Mobitz type I block in every patient","Permanent QT shortening","Ventricular pre-excitation"]', 'Tachycardia-induced cardiomyopathy', 'Sustained rapid ventricular rates may cause ventricular dilation and systolic dysfunction.', 'Atrial Fibrillation', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which ventricular rate is commonly associated with atrial flutter and 2:1 AV conduction?', '["Approximately 150 beats per minute","Approximately 30 beats per minute","Approximately 60 beats per minute","Approximately 250 beats per minute"]', 'Approximately 150 beats per minute', 'Typical flutter atrial rates near 300 with 2:1 conduction often produce a ventricular rate near 150.', 'Atrial Flutter', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Where is the re-entry circuit in typical AVNRT?', '["Within or near the AV node using fast and slow pathways","Around a ventricular infarct scar only","Exclusively within the pulmonary veins","Through the left bundle branch only"]', 'Within or near the AV node using fast and slow pathways', 'AVNRT depends on dual AV-nodal pathways with different conduction and refractory properties.', 'SVT', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Why is the QRS usually narrow in orthodromic AVRT?', '["Antegrade ventricular activation occurs through the AV node and His-Purkinje system","The accessory pathway blocks all ventricular activation","The impulse begins in ventricular scar","The rhythm is always paced"]', 'Antegrade ventricular activation occurs through the AV node and His-Purkinje system', 'Orthodromic AVRT uses the normal conduction system in the forward direction.', 'SVT', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Which triad suggests Wolff-Parkinson-White pattern in sinus rhythm?', '["Short PR interval, delta wave, and widened QRS","Long PR interval, narrow QRS, and U waves","Absent P waves, narrow QRS, and regular RR intervals","Progressive PR prolongation, dropped QRS, and bradycardia"]', 'Short PR interval, delta wave, and widened QRS', 'Accessory-pathway pre-excitation shortens the PR interval and slurs the initial QRS upstroke.', 'Pre-excitation', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which drug must be avoided in pre-excited atrial fibrillation?', '["Adenosine","Procainamide","Magnesium for Torsades","Epinephrine during cardiac arrest"]', 'Adenosine', 'AV-nodal blockade may divert more impulses down the accessory pathway and precipitate VF.', 'Pre-excitation', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('What is the most common substrate for monomorphic VT in a patient with previous MI?', '["Re-entry around ventricular scar","Pulmonary-vein automaticity","AV-nodal dual pathways","Sinus-node fibrosis alone"]', 'Re-entry around ventricular scar', 'Post-infarction scar creates regions of slow conduction that support re-entry.', 'Ventricular Arrhythmia', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Which description best identifies Torsades de pointes?', '["Polymorphic VT with QRS complexes twisting around the baseline","Regular narrow tachycardia with hidden P waves","Flatline without electrical activity","Progressive PR prolongation"]', 'Polymorphic VT with QRS complexes twisting around the baseline', 'Torsades is a characteristic polymorphic VT associated with prolonged repolarization.', 'Ventricular Arrhythmia', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('What is first-line drug treatment for Torsades de pointes?', '["Intravenous magnesium","Verapamil","Digoxin","Adenosine"]', 'Intravenous magnesium', 'Magnesium is first-line therapy and should be accompanied by correction of precipitating factors.', 'Ventricular Arrhythmia', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which antiarrhythmic class slows phase 0 depolarization in fast-response tissue?', '["Class I sodium-channel blockers","Class II beta-blockers only","Class III potassium-channel blockers","Class IV calcium-channel blockers only"]', 'Class I sodium-channel blockers', 'Class I drugs primarily block fast sodium channels and slow phase 0.', 'Pharmacology', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which class IA effect increases the risk of Torsades de pointes?', '["QT prolongation","Marked QT shortening","Complete suppression of potassium current without repolarization change","Selective funny-current activation"]', 'QT prolongation', 'Class IA drugs prolong action-potential duration and QT interval.', 'Pharmacology', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Which class IB drug is useful for acute post-MI ventricular arrhythmias?', '["Lidocaine","Verapamil","Diltiazem","Adenosine"]', 'Lidocaine', 'Class IB drugs preferentially affect ischemic or depolarized ventricular tissue.', 'Pharmacology', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which drug is contraindicated in structural or ischemic heart disease because of class IC proarrhythmia?', '["Flecainide","Esmolol","Magnesium","Atropine"]', 'Flecainide', 'Flecainide and propafenone are strong sodium-channel blockers with dangerous proarrhythmic effects in structural disease.', 'Pharmacology', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('How do beta-blockers affect pacemaker cells?', '["They reduce the slope of phase 4 depolarization","They increase the funny current","They directly create a delta wave","They abolish potassium efflux in phase 3"]', 'They reduce the slope of phase 4 depolarization', 'Reduced sympathetic signaling decreases automaticity and AV-nodal conduction.', 'Pharmacology', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which class III agents are especially associated with Torsades risk?', '["Sotalol and ibutilide","Lidocaine and mexiletine","Metoprolol and esmolol","Verapamil and diltiazem"]', 'Sotalol and ibutilide', 'These potassium-channel blockers prolong the QT interval and may provoke Torsades.', 'Pharmacology', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Which extracardiac toxicities are characteristic of amiodarone?', '["Pulmonary, thyroid, and hepatic toxicity","Isolated renal stones only","Pure bone-marrow suppression only","Selective retinal detachment only"]', 'Pulmonary, thyroid, and hepatic toxicity', 'Amiodarone has broad systemic toxicity despite a comparatively lower Torsades risk.', 'Pharmacology', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which drugs are class IV antiarrhythmics?', '["Verapamil and diltiazem","Quinidine and procainamide","Flecainide and propafenone","Amiodarone and sotalol"]', 'Verapamil and diltiazem', 'Non-dihydropyridine calcium-channel blockers slow AV-nodal conduction.', 'Pharmacology', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('What is the main clinical use of adenosine in arrhythmia management?', '["Termination or diagnosis of stable AV-node-dependent SVT","Long-term anticoagulation in AF","Treatment of complete heart block","Definitive therapy for ventricular scar"]', 'Termination or diagnosis of stable AV-node-dependent SVT', 'Adenosine produces a brief AV-nodal block and has an ultra-short duration of action.', 'Pharmacology', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which substance can blunt the effect of adenosine?', '["Caffeine","Magnesium","Potassium","Atropine"]', 'Caffeine', 'Caffeine and theophylline antagonize adenosine receptors and can reduce its effect.', 'Pharmacology', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Which combination suggests digoxin toxicity?', '["Nausea, yellow vision, and arrhythmias","Dry cough, hemoptysis, and narrow pulse pressure","Polyuria, hypernatremia, and bradycardia only","Isolated fever and rash"]', 'Nausea, yellow vision, and arrhythmias', 'Digoxin toxicity commonly produces gastrointestinal symptoms, visual disturbance, and diverse arrhythmias.', 'Pharmacology', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('Which electrolyte abnormality increases susceptibility to digoxin toxicity?', '["Hypokalemia","Hypernatremia","Hyperphosphatemia","Isolated hyperchloremia"]', 'Hypokalemia', 'Hypokalemia dangerously exacerbates digoxin toxicity and increases arrhythmic risk.', 'Pharmacology', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('What is the recommended adult chest-compression rate in the source?', '["100 to 120 per minute","40 to 60 per minute","140 to 160 per minute","Exactly 80 per minute"]', '100 to 120 per minute', 'High-quality CPR uses 100 to 120 compressions per minute.', 'BLS', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('What is the recommended adult chest-compression depth in the source?', '["At least 5 cm but not more than about 6 cm","Exactly 1 cm","At least 8 cm","No depth target is used"]', 'At least 5 cm but not more than about 6 cm', 'Adequate depth and complete recoil are essential, while excessive depth should be avoided.', 'BLS', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('What compression-to-ventilation ratio is used in adults without an advanced airway?', '["30:2","15:1","5:1","Continuous compressions with no breaths"]', '30:2', 'The source specifies 30 compressions followed by 2 breaths before advanced-airway placement.', 'BLS', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('After placement of an advanced airway, how often should breaths be delivered during continuous compressions?', '["One breath every 6 seconds","One breath every second","Two breaths every 30 compressions with pauses","No ventilation is required"]', 'One breath every 6 seconds', 'Continuous compressions are paired with approximately 10 breaths per minute.', 'BLS', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('How frequently should the compressor ideally rotate to reduce fatigue?', '["Approximately every 2 minutes","Every 20 minutes","Only after ROSC","After every 30 compressions"]', 'Approximately every 2 minutes', 'Rotation every two minutes helps preserve compression quality.', 'BLS', 'core', 'medical', 'Cardiology', 'Arrhythmia'),
('What is the minimum MAP target described after ROSC?', '["Approximately 65 mmHg","Approximately 30 mmHg","Exactly 120 mmHg in every patient","No blood-pressure target is needed"]', 'Approximately 65 mmHg', 'Hypotension should be avoided, with a minimum MAP around 65 mmHg individualized to the patient.', 'Post-Arrest Care', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('What oxygen-saturation range is described after reliable oximetry becomes available post-ROSC?', '["90% to 98%","50% to 60%","Exactly 100% indefinitely","75% to 80%"]', '90% to 98%', 'Oxygen should be titrated to avoid both hypoxemia and hyperoxemia.', 'Post-Arrest Care', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Which post-ROSC patient requires protocolized temperature control according to the source?', '["A patient who remains unresponsive or comatose","Every patient with a normal neurologic examination","Only patients with first-degree AV block","Only patients younger than 18 years"]', 'A patient who remains unresponsive or comatose', 'Comatose patients after ROSC require controlled temperature and active fever prevention.', 'Post-Arrest Care', 'advanced', 'medical', 'Cardiology', 'Arrhythmia'),
('Persistent ST elevation after ROSC should prompt consideration of what?', '["Urgent coronary angiography","Routine AV-nodal blockade","Immediate permanent pacemaker in every case","No cardiac investigation"]', 'Urgent coronary angiography', 'Persistent ST elevation or strong suspicion of acute coronary occlusion supports urgent angiography.', 'Post-Arrest Care', 'advanced', 'medical', 'Cardiology', 'Arrhythmia');
